# Skeptic: only packet-taught patterns; explicit I/O contract
def assess(record: dict) -> str:
    required = {'blob_store', 'transactions', 'cache_ttl_s', 'case_id', 'cache_authoritative'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    if record.get("cache_authoritative") is False and record.get("transactions") != "cache":
        return 'PASS'
    return 'REDESIGN_PERSISTENCE'

valid = {"case_id": 'CASO-SYN-1A', 'blob_store': 'object', 'transactions': 'relational', 'cache_authoritative': False, 'cache_ttl_s': 300}
adverse = {"case_id": 'CASO-SYN-1A-ADV', 'blob_store': 'object', 'transactions': 'cache', 'cache_authoritative': True, 'cache_ttl_s': 300}
missing = {k: valid[k] for k in valid if k != 'cache_ttl_s'}
print(assess(valid))
print(assess(adverse))
print(assess(missing))

